Use MAUI's `App` lifecycle events combined with `Preferences` for lightweight persistence:

```csharp
// In App.xaml.cs
public partial class App : Application
{
    public App()
    {
        InitializeComponent();
        MainPage = new NotePage();
    }

    protected override Window CreateWindow(IActivationState? activationState)
    {
        var window = base.CreateWindow(activationState);

        window.Deactivated += (s, e) =>
        {
            if (MainPage is NotePage page)
                page.SaveDraft();
        };

        window.Activated += (s, e) =>
        {
            if (MainPage is NotePage page)
                page.RestoreDraft();
        };

        return window;
    }
}
```

```csharp
// In NotePage.xaml.cs
public partial class NotePage : ContentPage
{
    private const string DraftKey = "NoteDraft";

    public NotePage()
    {
        InitializeComponent();
        RestoreDraft();
    }

    public void SaveDraft()
    {
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    public void RestoreDraft()
    {
        NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    // Call this when the user explicitly saves/discards
    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }
}
```

```xml
<!-- NotePage.xaml (relevant part) -->
<Editor x:Name="NoteEditor" Placeholder="Type your note..." />
```

**Key points:**

- **`Window.Deactivated`** fires when the app backgrounds — save here.
- **`Window.Activated`** fires on resume — restore here.
- **`Preferences`** is ideal for small strings; for larger data, use `SecureStorage` or file I/O.
- Call `ClearDraft()` when the user intentionally saves or discards, so stale drafts don't reappear.
